$_MODULE['<{facebookconversiontrackingplus}prestashop>configuration_6de38c10d8ce49eda84b4d1bf70e6a93'] = 'Après la configuration de votre identifiant Pixel, Facebook commencera à développer votre audience, qui sera utilisée ultérieurement dans vos campagnes de remarketing/reciblage';
$_MODULE['<{facebookconversiontrackingplus}prestashop>configuration_3a62560339c50d9ba0ee1344f5a1f702'] = 'À chaque visite de votre site Web, votre audience augmentera (à condition que les visiteurs soient connectés à Facebook)';
$_MODULE['<{facebookconversiontrackingplus}prestashop>configuration_486360a9e9ffee90b7c69ff0499b19de'] = 'Une fois que votre audience sera suffisamment importante, vous pourrez commencer à générer vos propres audiences personnalisées à partir des données de votre audience. Vous pourrez créer une audience très large ou une audience ciblée (par exemple, les personnes qui ont visité une certaine catégorie)';
$_MODULE['<{facebookconversiontrackingplus}prestashop>configuration_4409393501bfa9956be52133a8e670c4'] = 'Vous avez également la possibilité de créer autant d\'audiences personnalisées que vous le souhaitez';
$_MODULE['<{facebookconversiontrackingplus}prestashop>configuration_c61b94598a01caefac66ac5a2b59c790'] = 'Pour consulter vos audiences, accédez à Gestionnaires des annonces > Outils > Audiences';
$_MODULE['<{facebookconversiontrackingplus}prestashop>configuration_432be4d556706a0ae907243807fee165'] = 'Après avoir créé des audiences, vous pourrez les utiliser dans la section « Audiences » lors de la création de campagnes publicitaires';
$_MODULE['<{facebookconversiontrackingplus}prestashop>configuration_162fda42e67e7a574f9cca23029dd6af'] = 'L\'outil « Audiences similaires » permet de générer une audience en choisissant des personnes qui ont des préférences similaires aux vôtres. Cela vous permet de cibler vos campagnes publicitaires %s sur des clients potentiels';
