$_MODULE['<{facebookconversiontrackingplus}prestashop>configuration_28beec6cae50771938f4afccb0a79088'] = 'Création d\'un catalogue';
$_MODULE['<{facebookconversiontrackingplus}prestashop>configuration_5f0977fa90bac08c400e40e5eec95023'] = 'Vous pouvez également créer un catalogue basé sur des événements à l\'aide du module Pixel Plus. Les catalogues de ce type sont faciles à créer et à gérer : il suffit de fournir les microdonnées correspondantes et d\'inciter vos visiteurs à consulter vos produits';
$_MODULE['<{facebookconversiontrackingplus}prestashop>configuration_d507171648fbe010ca156c0fa5fe34bd'] = 'Microdonnées';
$_MODULE['<{facebookconversiontrackingplus}prestashop>configuration_9098e86a8dd28e0af3395790bce8fcaa'] = 'Pour créer un catalogue basé sur des événements, vous devez disposer des bonnes microdonnées';
$_MODULE['<{facebookconversiontrackingplus}prestashop>configuration_73ed2245f3417748bfb0c2adb720d541'] = 'Accédez à la section Microdonnées du module, activez la deuxième sélection, puis enregistrez';
