$_MODULE['<{facebookconversiontrackingplus}prestashop>configuration_413d55bb954e48564e69cb4e1704a6da'] = 'Si vous voyez la mention « pas prêt » à côté d\'un pixel, cela signifie que vous devrez attendre un peu plus longtemps';
$_MODULE['<{facebookconversiontrackingplus}prestashop>configuration_a257f5ce51ca09d718b83012766fdfa3'] = 'Après avoir ajouté les microdonnées nécessaires à votre page, la validation du Pixel par Facebook nécessitera un certain délai (jusqu\'à 48 heures)';
$_MODULE['<{facebookconversiontrackingplus}prestashop>configuration_adeb2df5a52c8170e6a481b238829203'] = 'Vous pouvez accélérer ce processus en parcourant certains produits et en effectuant certaines activités sur votre site Web';
$_MODULE['<{facebookconversiontrackingplus}prestashop>configuration_6312333958fa878db206ffaeac4a8736'] = 'Lorsque le pixel sera prêt, vous pourrez l\'utiliser comme source de produits';
$_MODULE['<{facebookconversiontrackingplus}prestashop>configuration_8d726a403b1d7f202536522ade01b72e'] = 'Les catalogues basés sur des événements fonctionnent selon l\'événement ViewContent (l\'événement qui est envoyé lorsqu\'un produit est consulté). Par conséquent, les produits seront ajoutés au catalogue dès qu\'ils seront consultés par des visiteurs';
$_MODULE['<{facebookconversiontrackingplus}prestashop>configuration_9dae6ff3956754f6f7f921cce14f53f7'] = 'Association des catégories de Google';
$_MODULE['<{facebookconversiontrackingplus}prestashop>configuration_4909c75ccec3560bb58311283ad54b2f'] = 'Google a développé une structure de catégories afin d\'avoir un système de catégories standardisé';
$_MODULE['<{facebookconversiontrackingplus}prestashop>configuration_dd3e2e7c01ff6eedccffedc4196b48dc'] = 'Plusieurs plateformes, comme Facebook, utilisent cette structure pour mieux définir les catégories  auxquelles appartiennent vos produits';
$_MODULE['<{facebookconversiontrackingplus}prestashop>configuration_bbe2843c16048d55427c9bc65a348c15'] = 'Pour établir un lien entre vos catégories et celles de Google, accédez à la section \"%s\"';
