$_MODULE['<{facebookconversiontrackingplus}prestashop>csv-creation-alert_0a717b441fafc03187a7fac8db669f49'] = 'La liste de diffusion est vide';
$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_2e81067cd8e5369ca868ad3bdbe2ff43'] = 'Cela est certainement dû à un bloqueur de publicités. Désactivez votre bloqueur de publicités et actualisez votre site. Les événements devraient revenir en vert.';
$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_80a40fc0de9182f2a588b68aca0b37d2'] = 'Tout d\'abord, ouvrez et lisez le message d\'erreur correspondant pour obtenir plus d\'informations.';
$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_32c3c0a326a80418b03624175a635583'] = 'Si vous avez encore des doutes après avoir lu le message, consultez la FAQ suivante pour consulter une description des erreurs les plus courantes';
$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_41d83d6a25b1c360489d070dc2122295'] = 'C\'est l\'un des messages les plus courants. Cela est dû au fait que le module a plusieurs événements dynamiques, et que ces événements ne seront envoyés à Facebook que lorsqu\'une action se produira.';
$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_1f7aadb49a5f7d2ae512c784bc1a8f98'] = 'Exemples :';
$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_b64c83286ace832c0ec837ac4c1c8057'] = 'Ajouter au panier';
$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_36d528c080494038562def21d0815a54'] = 'À moins qu\'un produit ne soit ajouté au panier, il n\'est pas utile d\'envoyer les données à Facebook';
