$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_e8b7475737fb954fbac4dc71fa779f8a'] = 'Inscription terminée';
$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_4c4d2990c999fe1db1e966439451c852'] = 'Se déclenche de manière dynamique après l\'inscription d\'un client. Peut être difficile à voir avec le Pixel Helper';
$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_0718b27453e1f8c6cb8d374fef7c96b7'] = 'Lancer le paiement';
$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_31087ae942a3e65721ae8a58e14f839d'] = 'Lorsque le processus de paiement commence, il peut parfois être difficile à voir avec le Pixel Helper';
$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_ce25ea175997fc43086e3ffd774f91d4'] = 'Ajouter une méthode de paiement';
$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_0c7e7eb519c7b1abaab475721988f0a9'] = 'Lorsque l\'utilisateur sélectionne le mode de paiement à utiliser. Étant donné que les pages tierces ne peuvent pas être suivies (p.ex. PayPal), le module envoie l\'événement lorsque le mode de paiement est sélectionné';
$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_652cedd68d63aaf5808a1169326ada3f'] = 'Alternative à %s pour vérifier les événements Pixel : %s';
$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_3da5138bc7586c0aff30f2fb3d6930b6'] = 'Cette fonctionnalité est accessible depuis le Gestionnaire d\'annonces de Facebook > Pixel> Détails > Événements de test';
$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_10abbcdfcf086081145b693d12a85daf'] = 'Des erreurs peuvent se produire lors de la saisie de l\'identifiant.';
