$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_64e86256b03c6e498f9a535dc54a0ab4'] = 'Copiez l\'identifiant et allez dans la page de configuration du module';
$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_db6e2c2a8f5daee9b92b56edfe388470'] = 'Cliquez sur la section Flux et saisissez l\'identifiant du catalogue dans le champ correspondant';
$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_a8c4ccfead243ef2d242009383ee33ed'] = 'Le module dispose d\'un triple filtrage pour éviter les doublons, mais plusieurs éléments peuvent empêcher Facebook d\'avoir le nombre exact d\'événements d\'achats.';
$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_c8ca37608650cae7edf6a2bb4b2d914a'] = 'Événements d\'achats manquants :';
$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_ad95726b35cf144d5058b37d48e6c140'] = 'Cela est généralement dû à un bloqueur de publicités. C\'est un dysfonctionnement indépendant du module.';
$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_cc0445f72b30759cb53c6b82db294014'] = 'Les modules de paiement qui chargent une page intermédiaire peuvent également provoquer ce dysfonctionnement. Dans ce cas, il vous suffit d\'activer l\'option ';
$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_24e8ac50b8118374d041f62912a4d850'] = 'Événements d\'achats en double :';
$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_de62e22ac415d3eb9240b1023175b855'] = 'Cela est généralement dû à des moteurs de cache comme des modules de cache non natifs ou à des logiciels tiers comme CloudFlare.';
$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_4e15b0b357e2427f306fd8f61e1a56dc'] = 'Par défaut, le module ne s\'appuie pas sur la page de remerciement pour afficher l\'événement d\'achat. Cela le rend compatible avec n\'importe quel module de paiement, quelle que soit la page de retour après le paiement. Cependant, les moteurs de cache ont tendance à mettre en cache les envois du module, ce qui crée une répétition qui n\'est pas nécessaire.';
$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_53f0d8f2e081eb6375416a5331275d5a'] = 'Dans ce cas, activez l\'option ';
$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_5d167d92ce03c8db70da784b1b5001b4'] = 'Cependant, certains caches sont parfois très volumineux et peuvent ignorer le triple filtrage appliqué par le module';
$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_f7cee7aa810ddefb08c52bd6693b39c5'] = 'Oui ! Le pixel Facebook est initialisé sur l\'en-tête de la page, ce qui signifie que vous pouvez déclencher (envoyer) un événement sur n\'importe quelle page. Ceci est utile lorsque vous souhaitez ajouter l\'événement principal, par exemple en le liant à un certain bouton';
$_MODULE['<{facebookconversiontrackingplus}prestashop>faq_1fe917b01f9a3f87fa2d7d3b7643fac1'] = 'FAQ';
